import { 
    Orientation, 
    AnimQuery, 
    HasAudio,
    LayerName,
    LayerPresence 
} from './Classes';
import { Anim } from './animation_formats/0_6_X/AnimV0_6_X';
import { Layer, BodyKF, EventKF, EyeKF } from './animation_formats/0_6_X/AnimV0_6_X';
import { LayerTemplate } from './animation_formats/LayerMocks';

const BODY_ANGLE_EPSILON = 3;
const HOLD_SAFE_EVENT_NAME = 'HOLD_SAFE';


/**
 * @typedef LayerHandler<T>
 * @description Function type that handles a layer argument.
 * @memberof jibo.animdb
 * @internal
 */
export interface LayerHandler<T> {
    (l: Layer<T>): void;
}


/**
 * @class AnimUtils
 * @memberof jibo.animdb
 * @internal
 */
export class AnimUtils {

    /**
     * Add/Remove layers to/from animation based on a LayerPresence object
     * @method jibo.animdb.AnimUtils#syncAnimLayers
     * @static
     * @param {jibo.animdb#Anim} animData Animation data (for example loaded from keys file) - Animation data (for example loaded keys file object)
     * @param {jibo.animdb#LayerPresence} layers Which layers to select
     */
    static syncAnimLayers(animData: Anim, layers: LayerPresence) {
        // Remove all layers the animation has that weren't requested
        for (let layer = animData.layers.length - 1; layer >= 0; layer--) {
            let type = animData.layers[layer].type;
            if (!LayerName[type]) {  // If the layer looking at is a "long" layer (e.g. "Audio Event")
                type = type.replace(/\s/g, '');
            }
            if (layers[type] !== undefined && !layers[type]) {
                animData.layers.splice(layer, 1);
            }
        }

        // Remove all layers the animation doesn't have that weren't requested
        Object.keys(layers).forEach( layer => {
            if (!layers[layer]) {
                delete layers[layer];
            }
        });

        // Add all layers the animation doesn't have that were requested
        const layersToAdd = Object.keys(layers).filter( key => !AnimUtils.hasLayer(animData, LayerName[key], false) );
        layersToAdd.forEach(layerType => AnimUtils._addMockLayer(animData, LayerName[layerType].long || LayerName[layerType].short));
    }

    /**
     * Add layer of requested type to animation
     * @method jibo.animdb.AnimUtils#_addMockLayer
     * @static
     * @private
     * @param {jibo.animdb#Anim} animData Animation data (for example loaded from keys file)
     * @param {string} type Layer type
     */
    static _addMockLayer(animData: Anim, type: string) {
        animData.layers.push(LayerTemplate.generateLayer(type, type));
    }

    /**
     * Scales the time values of all animation keyframes with a number,
     * also affects animation duration
     * @method jibo.animdb.AnimUtils#scaleTimeInPlace
     * @static
     * @param {jibo.animdb#Anim} animData Animation data (for example loaded from keys file)
     * @param {number} scale Scale multiplier
     */
    static scaleTimeInPlace(animData: Anim, scale: number) {
        animData.layers.forEach( (layer) => {
            layer.keyframes.forEach( kf => {
                kf.time = Math.round(kf.time * scale);
            });
        });

        animData.duration = Math.round(animData.duration * scale);
    }

    /**
     * Scales the body DoF value with a number
     * @method jibo.animdb.AnimUtils#scaleBodyInPlace
     * @static
     * @param {jibo.animdb#Anim} animData Animation data (for example loaded from keys file)
     * @param {number} scale Scale multiplier
     */
    static scaleBodyInPlace(animData: Anim, scale: number) {
        AnimUtils.forEachLayerType(animData, LayerName.Body, (layer: Layer<BodyKF>) => {
            layer.keyframes.forEach( kf => {
                kf.value.Head *= scale;
                kf.value.Pelvis *= scale;
                kf.value.Torso *= scale;
            });
        });
    }

    /**
     * Flips eye and textures left/right
     * @method jibo.animdb.AnimUtils#flipScreenLeftRight
     * @static
     * @param {jibo.animdb#Anim} animDataAnimation data (for example loaded from keys file)
     */
    static flipScreenLeftRight(animData: Anim) {

        let handler = (layer: Layer<EyeKF>) => {
            layer.keyframes.forEach( kf => {
                kf.value.Translate.x *= -1;
            });
        };

        AnimUtils.forEachLayerType(animData, LayerName.Eye, handler);
        AnimUtils.forEachLayerType(animData, LayerName.Overlay, handler);
    }

    /**
     * Checks to see if the body starts in a neutral position
     * @method jibo.animdb.AnimUtils#startsNeutral
     * @static
     * @param {jibo.animdb#Anim} animData Animation data (for example loaded from keys file)
     * @returns {boolean}
     * @private
     */
    static startsNeutral(animData: Anim) {
        let ret = true;
        let earliestFrame = animData.duration;
        AnimUtils.forEachLayerType(animData, LayerName.Body, (layer: Layer<BodyKF>) => {
            if (layer.keyframes.length) {
                let kf = layer.keyframes[0];
                if (kf.time < earliestFrame) {
                    earliestFrame = kf.time;
                    if (Math.abs(kf.value.Pelvis) > BODY_ANGLE_EPSILON ||
                        Math.abs(kf.value.Head) > BODY_ANGLE_EPSILON ||
                        Math.abs(kf.value.Torso) > BODY_ANGLE_EPSILON) {
                        ret = false;
                    }
                }
            }
        });

        return ret;
    }

    /**
     * Checks to see if the body ends in a neutral position
     * @method jibo.animdb.AnimUtils#endsNeutral
     * @static
     * @param {jibo.animdb#Anim} animData  Animation data (for example loaded from keys file)
     * @returns {boolean}
     * @private
     */
    static endsNeutral(animData: Anim) {
        let ret = true;
        let latestTime = -1;
        AnimUtils.forEachLayerType(animData, LayerName.Body, (layer: Layer<BodyKF>) => {
            if (layer.keyframes.length) {
                let kf = layer.keyframes[layer.keyframes.length - 1];
                if (kf.time > latestTime) {
                    latestTime = kf.time;
                    if (Math.abs(kf.value.Pelvis) > BODY_ANGLE_EPSILON ||
                        Math.abs(kf.value.Head) > BODY_ANGLE_EPSILON ||
                        Math.abs(kf.value.Torso) > BODY_ANGLE_EPSILON) {
                        ret = false;
                    }
                }
            }
        });

        return ret;
    }

    /**
     * Checks each layer of the provided animation for content and returns the status of each layer
     * @method jibo.animdb.AnimUtils#checkLayers
     * @static
     * @param {jibo.animdb#Anim} animData  Animation data (for example loaded from keys file)
     * @param {boolean} [strict=true] Toggle for whether empty layers should be counted or not (default to not)
     * @returns {LayerPresence}
     * @private
     */
    static checkLayers(animData: Anim, strict=true): LayerPresence {
        let layerPresence = {} as LayerPresence;

        LayerName.Layers.forEach( layerName => {
            if (AnimUtils.hasLayer(animData, layerName, strict)) {
                layerPresence[layerName.short] = true;
            }
        });

        return layerPresence;
    }

    /**
     * Checks to see if animation has audio
     * @method jibo.animdb.AnimUtils#hasAudio
     * @static
     * @param {jibo.animdb#Anim} animData  Animation data (for example loaded from keys file)
     * @returns {boolean}
     * @private
     */
    static hasAudio(animData: Anim): boolean {
        return AnimUtils.hasLayer(animData, LayerName.AudioEvent);
    }

    /**
     * Checks to see if an animation has content in the requested layer
     * @method jibo.animdb.AnimUtils#hasLayer
     * @static
     * @param {jibo.animdb#Anim} animData  Animation data (for example loaded from keys file)
     * @param {jibo.animdb.LayerName} layerName Requested layer name
     * @param {boolean} [strict=true] Toggle for whether empty layers should be counted or not (default to not)
     * @returns {boolean}
     * @private
     */
    static hasLayer(animData: Anim, layerName: LayerName, strict=true): boolean {
        let layerCheck = [];

        AnimUtils.forEachLayerType(animData, layerName, (layer) => {
            if (strict) {
                layerCheck.push(layer.keyframes.length !== 0);
            } else {
                layerCheck.push(true);
            }
        });

        return layerCheck.some(hasContent => hasContent);
    }

    /**
     * Checks to see if animation has a hold safe keyframe
     * @method jibo.animdb.AnimUtils#hasHoldSafe
     * @static
     * @param {jibo.animdb#Anim} animData Animation data (for example loaded from keys file)
     * @param {string} name - Name of animation
     * @returns {number} -1 if none
     * @private
     */
    static hasHoldSafe(animData: Anim, name: string) {
        let kf = -1;
        AnimUtils.forEachLayerType(animData, LayerName.Event, (layer: Layer<EventKF>) => {
            layer.keyframes.forEach( layerKF => {
                if (layerKF.value.Event.name === HOLD_SAFE_EVENT_NAME) {
                    if (kf !== -1) {
                        throw new Error(`Two HOLD_SAFE keyframes defined in animation` +
                            ` '${name}' at frames ${kf} and ${layerKF.time}`);
                    }
                    kf = layerKF.time;
                }
            });
        });

        return kf;
    }

    /**
     * Attempts to auto extract orientation from animation
     * @method jibo.animdb.AnimUtils#calculateOrientation
     * @static
     * @param {jibo.animdb#Anim} animData  Animation data (for example loaded from keys file)
     * @returns {Orientation}
     * @private
     */
    static calculateOrientation(animData: Anim) {
        let headSum = 0;
        let pelvisSum = 0;
        let torsoSum = 0;
        let numFrames = 0;

        AnimUtils.forEachLayerType(animData, LayerName.Body, (layer: Layer<BodyKF>) => {
            layer.keyframes.forEach(layerKF => {
                numFrames++;
                headSum += layerKF.value.Head;
                pelvisSum += layerKF.value.Pelvis;
                torsoSum += layerKF.value.Torso;
            });
        });

        headSum /= numFrames;
        pelvisSum /= numFrames;
        torsoSum /= numFrames;

        // If we moved the body significantly then we only pay attention to that
        let bodySum = (torsoSum + pelvisSum) / 2;
        if (Math.abs(bodySum) > 10) {
            return (bodySum > 0) ? Orientation.LEFT : Orientation.RIGHT;
        }
        else {
            return (headSum > 0) ? Orientation.LEFT : Orientation.RIGHT;
        }
    }

    /**
     * Iterates through all layers whose names begin with 'name'
     * @method jibo.animdb.AnimUtils#forEachLayerType
     * @static
     * @param {jibo.animdb#Anim} animData - Animation data (for example loaded from keys file) The actual animation object
     * @param {jibo.animdb.LayerName} layerName Name gets matched with beginning of layer names
     * @param {Function} handler - Handler function for the layer
     */
    static forEachLayerType(animData: Anim, layerName: LayerName, handler: LayerHandler<any>) {
        let name = layerName.long || layerName.short;
        let altName = name + ' #';
        animData.layers.forEach( layer => {
            if (layer.name === name || layer.name.startsWith(altName)) {
                handler(layer);
            }
        });
    }

    /**
     * Takes a possibly incomplete query object and inserts default values
     * @method jibo.animdb.AnimUtils#insertDefaultAnimQueryParams
     * @static
     * @param  {jibo.animdb#Anim} query Animation query
     * @mutates query
     */
    static insertDefaultAnimQueryParams(query: AnimQuery) {
        if (!query.categories) {
            query.categories = [];
        }

        if (query.category) {
            query.categories.push(query.category);
        }

        // Make all category requests lower case
        for (let i = 0; i < query.categories.length; i++) {
            query.categories[i] = query.categories[i].toLowerCase();
        }

        if (!query.includeMeta) {
            query.includeMeta = [];
        } else {
            // Make all including meta term filters lower case
            for (let i = 0; i < query.includeMeta.length; i++) {
                query.includeMeta[i] = query.includeMeta[i].toLowerCase();
            }
        }

        if (!query.excludeMeta) {
            query.excludeMeta = [];
        } else {
            // Make all excluding meta term filters lower case
            for (let i = 0; i < query.excludeMeta.length; i++) {
                query.excludeMeta[i] = query.excludeMeta[i].toLowerCase();
            }
        }

        if (!query.durationError) {
            query.durationError = 0;
        }

        // If duration is 0 then that's an invalid duration anyway
        if (!query.duration) {
            query.duration = -1;
        }

        if (typeof query.hasAudio === 'undefined') {
            query.hasAudio = HasAudio.DONT_CARE;
        }
    }
}

export {}
