import { Animation } from './Animation';
import { Category } from './Category';


/**
 * @typedef jibo.animdb#Orientation
 * @description Enum of orientation options.
 * @property LEFT {any} Animation left oriented.
 * @property RIGHT {any} Animation right oriented.
 */
export enum Orientation {
    /**
     * Animation Left oriented
     * @type {string}
     */
    LEFT = <any> 'LEFT',
    /**
     * Animation Right oriented
     * @type {string}
     */
    RIGHT = <any> 'RIGHT',
}

/**
 * @typedef jibo.animdb#AnimConfig
 * @description Interface of configurations.
 * @property [duration] {number} Desired duration of animation in frames.
 * @property [speed] {number} Desired speed of animation (relative to 1 as normal).
 * @property [scale] {number} Desired scale multiplier for body DoFs.
 * @property [orientation] {jibo.animdb#Orientation} Desired orientation of the animation (left or right sided).
 * @property [layers] {jibo.animdb#LayerPresence} Desired layers to be present in animation.
 */
export interface AnimConfig {

    duration?: number;
    speed?: number;
    scale?: number;
    orientation?: Orientation;
    layers?: LayerPresence;
}

/**
 * @typedef jibo.animdb#DOFOptions
 * @description Interface of DOF options to provide to DOFArbiter.
 * @property {boolean} allOrNothing `true` to still play on the acquired DOFs if the DOFArbiter
 * cannot acquire all the DOFs the animation is requesting.
 * `false` to not play the animation.
 */
export interface DOFOptions {
    allOrNothing: boolean;
}

/**
 * @typedef jibo.animdb#PlaybackOptions
 * @description Interface of playback options.
 * @property [forceReturnToIdle] {boolean} `true` to return Jibo to neutral pose after the animation finishes.
 * @property [screenCenterOverride] {boolean} `true` to center screen content before the animation plays.
 * @property [handleBuilder] {function} Takes any builder manipulations to configure for playback.
 * @property [handleAnimation] {function} Takes any animation instance.
 * @property [ownerInformation] {string} Name by which the DOFArbiter should track the requester.
 * @property [dofOptions] {jibo.animdb#DOFOptions} Options that affect the arbitration process.
 */
export interface PlaybackOptions {
    forceReturnToIdle?: boolean;
    screenCenterOverride?: boolean;
    handleBuilder?: (builder:any)=>void;
    handleAnimation?: (anim:any)=>void;
    ownerInformation?: string;
    dofOptions?: DOFOptions;
}

/**
 * @typedef jibo.animdb#HasAudio
 * @description Enum of audio options
 * @property YES {any} Animation has audio.
 * @property NO {any} Animation does not have audio.
 * @property DONT_CARE {any} Animation may or may not have audio.
 */
export enum HasAudio {
    YES = <any> 'YES',
    NO = <any> 'NO',
    DONT_CARE = <any> 'DONT_CARE'
}

/**
 * @typedef jibo.animdb#AnimQuery
 * @description Interface of query informaton.
 * @property [category] {string} Desired category name
 * @property [categories] {string[]} Multiple category names to pick from
 * @property [duration] {number} Desired animation duration in frames
 * @property [durationError] {number} Allowed duration error in frames
 * @property [hasAudio] {jibo.animdb#HasAudio} Whether animation can contain audio
 * @property [includeMeta] {string[]} List of meta tags that the animation must contain
 * @property [excludeMeta] {string[]} List of meta tags that the animation must not contain
 */
export interface AnimQuery {
    category?: string;
    categories?: string[];
    duration?: number;
    durationError?: number;
    hasAudio?: HasAudio;
    includeMeta?: string[];
    excludeMeta?: string[];
}

/**
 * @class AnimResults
 * @memberof jibo.animdb
 */
export class AnimResults {
    /**
     * Animations that match the query
     * @name jibo.animdb.AnimResults#matching
     * @type {jibo.animdb.Animation[]}
     */
    matching: Animation[] = [];
    /**
     * Animations that match the query but not the duration boundaries
     * @name jibo.animdb.AnimResults#nonMatching
     * @type {jibo.animdb.Animation[]}
     */
    nonMatching: Animation[] = [];
}

/**
 * @class SearchResults
 * @memberof jibo.animdb
 */
export class SearchResults {
    /**
     * Category that matches search string
     * @name jibo.animdb.SearchResults#category
     * @type {jibo.animdb.Category}
     */
    category: Category;
    /**
     * Animation whose name matches search string
     * @name jibo.animdb.SearchResults#name
     * @type {jibo.animdb.Category}
     */
    name: Animation;
    /**
     * Animations that match search string on meta tags
     * @name jibo.animdb.SearchResults#meta
     * @type {jibo.animdb.Category}
     */
    meta: Animation[] = [];
}


/**
 * @class LayerName
 * @memberof jibo.animdb
 * @description Layer types are: Body, Eye, EyeTexture, Overlay, OverylayTexture,
 * AudioEvent, Event, Pixi, BackgroundTexture, and LED. Glow and Lighting layers soon to be deprecated.
 */
export class LayerName {

    static Body = new LayerName('Body');
    static Eye = new LayerName('Eye');
    static EyeTexture = new LayerName('EyeTexture', 'Eye Texture');
    static Overlay = new LayerName('Overlay');
    static OverlayTexture = new LayerName('OverlayTexture', 'Overlay Texture');
    static AudioEvent = new LayerName('AudioEvent', 'Audio Event');
    static Event = new LayerName('Event');
    static Pixi = new LayerName('Pixi');
    static BackgroundTexture = new LayerName('BackgroundTexture', 'Background Texture');
    static LED = new LayerName('LED');
    static Glow = new LayerName('Glow');
    static Lighting = new LayerName('Lighting');
    static Layers = [
        LayerName.Body,
        LayerName.Eye,
        LayerName.EyeTexture,
        LayerName.Overlay,
        LayerName.OverlayTexture,
        LayerName.AudioEvent,
        LayerName.Event,
        LayerName.Pixi,
        LayerName.BackgroundTexture,
        LayerName.LED,
        LayerName.Glow,
        LayerName.Lighting
    ];

    constructor(public short: string, public long?: string) { }

}

/**
 * @typedef jibo.animdb#LayerPresence
 * @description Interface for layers present in the animation.
 * For more information on animation layers, see [Animation Editor](https://developers.jibo.com/docs/animation-editor.html#layers).
 * @property [Body] {boolean}
 * @property [Eye] {boolean}
 * @property [EyeTexture] {boolean}
 * @property [Overlay] {boolean}
 * @property [OverlayTexture] {boolean}
 * @property [AudioEvent] {boolean}
 * @property [Event] {boolean}
 * @property [Pixi] {boolean}
 * @property [BackgroundTexture] {boolean}
 * @property [LED] {boolean}
 * @property [Glow] {boolean}
 * @property [Lighting] {boolean}
 */
export interface LayerPresence {
    /**
     * @name jibo.animdb.LayerPresence#Body
     * @type {boolean}
     */
    Body?: boolean;
    /**
     * @name jibo.animdb.LayerPresence#Eye
     * @type {boolean}
     */
    Eye?: boolean;
    /**
     * @name jibo.animdb.LayerPresence#EyeTexture
     * @type {boolean}
     */
    EyeTexture?: boolean;
    /**
     * @name jibo.animdb.LayerPresence#Overlay
     * @type {boolean}
     */
    Overlay?: boolean;
    /**
     * @name jibo.animdb.LayerPresence#OverlayTexture
     * @type {boolean}
     */
    OverlayTexture?: boolean;
    /**
     * @name jibo.animdb.LayerPresence#AudioEvent
     * @type {boolean}
     */
    AudioEvent?: boolean;
    /**
     * @name jibo.animdb.LayerPresence#Event
     * @type {boolean}
     */
    Event?: boolean;
    /**
     * @name jibo.animdb.LayerPresence#Pixi
     * @type {boolean}
     */
    Pixi?: boolean;
    /**
     * @name jibo.animdb.LayerPresence#BackgroundTexture
     * @type {boolean}
     */
    BackgroundTexture?: boolean;
    /**
     * @name jibo.animdb.LayerPresence#LED
     * @type {boolean}
     */
    LED?: boolean;
    /**
     * @name jibo.animdb.LayerPresence#Glow
     * @type {boolean}
     */
    Glow?: boolean;
    /**
     * @name jibo.animdb.LayerPresence#Lighting
     * @type {boolean}
     */
    Lighting?: boolean;
}


/**
 * @typedef jibo.animdb#BuilderLayer
 * @description Enum of BuilderLayer options:
 * @property beat {string} 'beat'
 * @property default {string} 'default'
 * @property posture {string} 'posture'
 * @private
 */
export enum BuilderLayer {
    beat = <any> 'beat',
    default = <any> 'default',
    posture = <any> 'posture',
}

/**
 * @typedef jibo.animdb#PlayOptions
 * @description Options for playing the animation.
 * @property [layer] {jibo.animdb#BuilderLayer}
 * @property [root] {string}
 * @private
 */
export interface PlayOptions {
    layer?: BuilderLayer;
    root?: string;
}
