import { TimeUtils, PlaybackUtils, KeysPlayback, PromiseUtils, KeysPlaybackOptions } from 'jibo-cai-utils';
import { Anim } from './animation_formats/0_6_X/AnimV0_6_X';
import { PlaybackOptions, BuilderLayer, LayerName } from './Classes';
import { Animation } from './Animation';
import { AnimUtils } from './AnimUtils';


const FRAMERATE = 30;


/**
 * @class Playback
 * @memberof jibo.animdb
 * @param {number} duration - Desired duration
 * @param {number} speed - Desired speed
 * @param {number} _framesToHold - How many frames to hold on a hold safe keyframe
 * @param {string} _resourceRoot - Root directory for resources
 * @param {jibo.animdb.Anim} _animData - The anim data to be played
 * @param {jibo.animdb.Animation} _animation - Reference to the original animation
 */
export class Playback {

    public keysPlaybackPr: Promise<KeysPlayback>;
    private _audioOnly = false;

    /**
     * Creates a playback object
     */
    constructor(public duration: number,
                public speed: number,
                private _framesToHold: number,
                private _resourceRoot: string,
                private _animData: Anim,
                private _animation: Animation) {
        // noop
    }

    /**
     * Initializes the KeysPlayback object for the animation
     * @param {jibo.animdb#PlaybackOptions} [options] - Options that allow configuring playback of animation
     * @returns {Promise<KeysPlayback>}
     */
    init(options?: PlaybackOptions): Promise<KeysPlayback> {
        const jibo = this._animation.parent.parent.jibo;

        // Enables AUDIO EVENT-only animations to playback audio
        if (this._animData.layers.length === 1 && this._animData.layers[0].type === LayerName.AudioEvent.long) {
            AnimUtils._addMockLayer(this._animData, LayerName.Body.short);
            this._audioOnly = true;
        }

	let keysPlaybackOptions: KeysPlaybackOptions = {
	    jibo,
	    animData: this._animData,
	    rootPath: this._resourceRoot
	};
	keysPlaybackOptions.ownerInformation = (options && options.ownerInformation) ? options.ownerInformation : 'AnimDB';
	keysPlaybackOptions.dofOptions = (options && options.dofOptions) ? options.dofOptions : undefined;

	this.keysPlaybackPr = PlaybackUtils.createKeysPlayback(keysPlaybackOptions);
	return this.keysPlaybackPr;
    }

    /**
     * Plays the animation
     * @method jibo.animdb.Playback#play
     * @param {jibo.animdb#PlaybackOptions} [options] - Options that allow configuring playback of animation
     * @returns {Promise<void>}
     */
    play(options: PlaybackOptions = {}): Promise<void> {
        const jibo = this._animation.parent.parent.jibo;

        // Handle animation hold
        let holdHandler = (signal, playInst) => {
            // If play instance has pause method, then we pause
            if (playInst.setPaused) {
                playInst.setPaused(true);
                TimeUtils.wait(this._framesToHold / FRAMERATE * 1000)
                    .then(() => playInst.setPaused(false));
            }
        };

        // Initialize the KeysPlayback object (if not already done so)
        const _keysPlaybackPr = this.keysPlaybackPr || this.init(options);
        const builderConfigFn = builder => {
            builder.setSpeed(this.speed);
            builder.on('HOLD_SAFE', holdHandler);
            if (this._audioOnly) {
                builder.setLayer(BuilderLayer.beat);
            }
            if (options.handleBuilder) {
                options.handleBuilder(builder);
            }
        };

        return _keysPlaybackPr.then( keysPlayback => {
            return keysPlayback.play(builderConfigFn, options.handleAnimation, options.screenCenterOverride);
        }).then(() => {
            if (options.forceReturnToIdle) {
                // We fully return to neutral on the following DOF sets: [ BODY ]
                return PromiseUtils.promisify( h =>
                    jibo.animate.centerRobot(jibo.animate.dofs.BODY, null, h as ()=>void));
            }
        }).then(() => null);
    }
}
