import { Layer } from './0_6_X/AnimV0_6_X';
import { KeyFrameType } from './DataFormats';

let generateId = require('jibo-keyframes').generateId;


export class LayerTemplate {

    static generateLayer(name: string, type: string) {

        let layer = {} as Layer<KeyFrameType>;
        layer.id = generateId();
        layer.name = name;
        layer.type = type;
        layer.visible = true;
        layer.locked = false;
        layer.keyframes = [];

        return layer;
    }
}