import * as path from 'path';
import * as fs from 'fs';
import { FileUtils, PromiseUtils } from 'jibo-cai-utils';
import { Anim } from './animation_formats/0_6_X/AnimV0_6_X';
import { AnimDB } from './AnimDB';
import { AnimCollection } from './AnimCollection';
import { Animation, AnimMetadata } from './Animation';
import { Category } from './Category';
import { AnimUtils } from './AnimUtils';
import { Utils } from './Utils';
import { INFINITE_DURATION } from './Range';

const stringify = require('json-stable-stringify');


/**
 * @class AnimDBParser
 * @memberof jibo.animdb
 */
export class AnimDBParser {

    /**
     * Creates an animDB from a list of root directories
     * @method jibo.animdb.AnimDBParser#readAnimDB
     * @param {object} jibo - The jibo runtime
     * @param {string} animDBPath Path to an animDB json
     * @param {string[]} [moreAnimDBPaths] Paths to more animDB	 json
     * @returns {Promise<jibo.animdb.AnimDB>}
     */
    static readAnimDB(jibo: any, animDBPath: string, ...moreAnimDBPaths: string[]): Promise<AnimDB> {
        moreAnimDBPaths.unshift(animDBPath);

        let animDB = new AnimDB(jibo);

        let promises = moreAnimDBPaths.map( (rootDir) => {
            return AnimDBParser.readAndAddAnimCollection(animDB, rootDir);
        });

        return Promise.all(promises)
            .then(() => animDB);
    }

    /**
     * Creates an animDB instance from a particular root animation directory
     * @method jibo.animdb.AnimDBParser#readAndAddAnimCollection
     * @param {jibo.animdb.AnimDB} animDB - The animDB to add collection to
     * @param {string} animDBPath
     * @returns {Promise<jibo.animdb.AnimCollection>}
     */
    static readAndAddAnimCollection(animDB: AnimDB, animDBPath: string): Promise<void> {
        let rootDir = path.dirname(animDBPath);

        return FileUtils.readFile(animDBPath)
            .then(animStr => {
                let animObjects: any = JSON.parse(animStr);

                let collection = new AnimCollection(animDB);

                for (let animName of Object.keys(animObjects)) {
                    let animMeta = animObjects[animName];
                    animName = animMeta.name.toLowerCase();
                    let anim = new Animation(collection, animMeta, rootDir);

                    let existingAnim = collection.getAnimByName(anim.name);
                    if (existingAnim) {
                        let paths = [existingAnim.meta.path, animMeta.path];
                        throw new Error(`Duplicate animation name: '${animName}' at paths: ${paths}`);
                    }
                    collection.addAnimation(anim);

                    anim.meta.categories.forEach((categoryName) => {
                        let cat = collection.getCategoryByName(categoryName);
                        if (!cat) {
                            cat = new Category(categoryName);
                            collection.addCategory(cat);
                        }

                        cat.addAnimation(anim);
                    });
                }
                animDB.push(collection);
            });
    }

    /**
     * Finds all key files under a certain root dir (recursively), reads them and
     * extracts meta data from them.
     * Writes resulting metadata collection to a json object on disk
     * @method jibo.animdb.AnimDBParser#createAndWriteAnimMetaData
     * @param {Object} jibo - The jibo runtime
     * @param {string} rootDir Animations will be searched in rootDir/animations
     * @param {string} outName Name of output file (no extension)
     * @returns {Promise<any>}
     */
    static createAndWriteAnimMetaData(jibo: any, rootDir: string, outName: string): Promise<any> {
        return AnimDBParser.createAnimMetaData(jibo, rootDir)
            .then( allAnimData => {
                let outPath = path.join(rootDir, outName + '.json');
                let data = stringify(allAnimData, { space: '  ' });
                return PromiseUtils.promisify( h => fs.writeFile(outPath, data, 'utf8', h) );
            });
    }

    /**
     * Finds all key files under a certain root dir (recursively), reads them and
     * extracts meta data from them
     * @method jibo.animdb.AnimDBParser#createAnimMetaData
     * @param {Object} jibo - The jibo runtime
     * @param {string} rootDir Animations will be searched in rootDir/animations
     * @returns {Promise<object>} an object comprised of {@link jibo.animdb#AnimMetadata}.
     */
    static createAnimMetaData(jibo: any, rootDir: string): Promise<{[x:string]: AnimMetadata}> {
        let animsDir = path.join(rootDir, 'animations');

        return FileUtils.findAllFilesWithExt(animsDir, 'keys')
            .then((filePaths) => {
                const goodPaths = filePaths.filter( filePath => {
                    return !path.basename(filePath).startsWith('_');
                });

                const pr: Promise<AnimMetadata>[] = goodPaths.map(data => {
                    return AnimDBParser.parseAnimation(jibo, data);
                });
                return Promise.all(pr);
            })
            .then( _allAnimData => {
                let allAnimData: AnimMetadata[] = <any> _allAnimData;
                // Here we fix the paths to be relative to rootDir
                let rootDirResolved = path.resolve(rootDir);

                let out = {};
                allAnimData.forEach( animData => {

                    let firstPart = animData.path.substring(0, rootDirResolved.length);
                    if (firstPart !== rootDirResolved) {
                        throw new Error(`Animation doesn't have the expected root path: ${[animData.path, rootDirResolved]}`);
                    }

                    animData.path = animData.path.substring(rootDirResolved.length + path.sep.length);

                    if (out[animData.name]) {
                        let paths = [ out[animData.name].path, animData.path ];
                        throw new Error(`Duplicate animation name: '${animData.name}' at paths: ${paths}`);
                    }

                    out[animData.name] = animData;
                });
                return out;
            });
    }

    /**
     * Loads animation data from disk and calculates derived properties
     * @method jibo.animdb.AnimDBParser#parseAnimation
     * @param {Object} jibo - The jibo runtime
     * @param {string} filePath to animation
     * @returns {Promise<jibo.animdb#AnimMetadata>}
     */
    static parseAnimation(jibo: any, filePath: string): Promise<AnimMetadata> {
        return AnimDBParser.loadKeys(jibo, filePath)
            .then( animData => {
                return AnimDBParser.parseAnimationFromAnim(animData, filePath);
            });
    }

    /**
     * Loads animation data from disk and expanding resolving/"macro-expanding" any Reference layers
     * @method jibo.animdb.AnimDBParser#loadKeys
     * @param {Object} jibo - The jibo runtime
     * @param {string} keysPath to animation
     * @returns {Promise<jibo.animdb#Anim>}
     */
    static loadKeys(jibo: any, keysPath: string): Promise<Anim> {
        return new jibo.rendering.animation.KeysLoader(keysPath).load();
    }

    /**
     * Calculates derived properties from Anim object
     * @method jibo.animdb.AnimDBParser#parseAnimationFromAnim
     * @param {jibo.animdb#Anim} animData object Animation object
     * @param {string} filePath keys file JSON
     * @returns {jibo.animdb#AnimMetadata}
     */
    static parseAnimationFromAnim(animData: Anim, filePath: string): AnimMetadata {
        let animdbTag: any;
        let scale, speed, name;
        try {
            let defaultName = path.basename(filePath, path.extname(filePath));
            animdbTag = animData.animdb || {};

            name = Utils.parseString(animdbTag.name, defaultName);
            scale = [
                Utils.parseNumber(animdbTag.scaleMin, 1),
                Utils.parseNumber(animdbTag.scaleMax, 1) ];
            speed = [
                Utils.parseNumber(animdbTag.speedMin, 1),
                Utils.parseNumber(animdbTag.speedMax, 1) ];
        }
        catch (error) {
            throw new Error(`Error parsing animation at path '${filePath}': '${error}'`);
        }

        if ((speed[0] <= 0) || (speed[0] > speed[1])) {
            throw new Error(`Invalid speed bounds '${JSON.stringify(speed)}' for animation '${filePath}'`);
        }

        if (scale[0] > scale[1]) {
            throw new Error(`Invalid scale bounds '${JSON.stringify(scale)}' for animation '${filePath}'`);
        }

        let categoryString = animdbTag.categories || '';
        let categories = [];
        categoryString.split(',').forEach( category => {
            let catName = category.trim().toLowerCase();
            if (catName.length) {
                categories.push( catName );
            }
        });

        let metaString = animdbTag.meta || '';
        let metaTerms = [];
        metaString.split(',').forEach( _metaTerm => {
            let metaName = _metaTerm.trim().toLowerCase();
            if (metaName.length) {
                metaTerms.push( metaName );
            }
        });

        let holdSafeKF = AnimUtils.hasHoldSafe(animData, name);

        let durationRange = [
            speed[0] * animData.duration,
            speed[1] * animData.duration
        ];
        if (holdSafeKF !== -1) {
            durationRange[1] = INFINITE_DURATION;
        }

        // Here we determine all of the properties from the animation data
        let animMetadata: AnimMetadata = {
            name,
            scale,
            speed,
            durationRange,
            categories,
            metaTerms,
            holdSafeKF,
            path: filePath,
            duration: animData.duration,
            startsNeutral: AnimUtils.startsNeutral(animData),
            endsNeutral: AnimUtils.endsNeutral(animData),
            hasAudio: AnimUtils.hasAudio(animData),
            orientation: <any> AnimUtils.calculateOrientation(animData) as string,
            layers: AnimUtils.checkLayers(animData)
        };
        return animMetadata;
    }
}
